import React, { useState, useEffect } from 'react';
import { randomPicsumUrl } from '../utils/picsum';
import './WhyWhistle.css';

const FEATURES = [
  { seed: 11, title: 'Custom-made Invisible', desc: 'Tailored for your unique smile using precise 3D scanning and modelling technology.' },
  { seed: 22, title: 'Predictable Results', desc: 'An advanced 3D modelling algorithm charts your exact tooth movement at every step.' },
  { seed: 33, title: 'Partnership with Clove Dental', desc: 'Closely tied to leading dental clinics for in-person check-ins and expert oversight.' },
  { seed: 44, title: 'Unbonded Aligners', desc: 'No buttons, no attachments. Remove any time — eat, brush, and smile freely.' },
];

export default function WhyWhistle() {
  const [featureImages, setFeatureImages] = useState(FEATURES.map((feature) => randomPicsumUrl(280, 200)));

  useEffect(() => {
    setFeatureImages(FEATURES.map((feature) => randomPicsumUrl(280, 200)));
  }, []);

  return (
    <section className="why-section">
      <div className="why-inner">
        <h2 className="why-title">Why Whistle?</h2>
        <div className="why-grid">
          {FEATURES.map((f, i) => (
            <div key={i} className="why-card">
              <img src={featureImages[i]} alt={f.title} className="why-img image-hover-scale" />
              <h3 className="why-card-title">{f.title}</h3>
              <p className="why-card-desc">{f.desc}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
